def bubble_sort(arr):
    n = len(arr)
    for i in range(n - 1):
        for j in range(0, n - i - 1):
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
    return arr

def optimized_bubble_sort(arr):
    n = len(arr)
    for i in range(n - 1):
        swapped = False
        for j in range(0, n - i - 1):
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
                swapped = True
        if not swapped:
            break
    return arr

if __name__ == '__main__':
    # Örnek Kullanım
    arr1 = [64, 34, 25, 12, 22, 11, 90]
    print(f"Original array (standard): {arr1}")
    bubble_sort(arr1)
    print(f"Sorted array (standard): {arr1}")

    arr2 = [5, 1, 4, 2, 8]
    print(f"Original array (optimized): {arr2}")
    optimized_bubble_sort(arr2)
    print(f"Sorted array (optimized): {arr2}")

    arr3 = [1, 2, 3, 4, 5] # Zaten sıralı bir dizi
    print(f"Original array (optimized, already sorted): {arr3}")
    optimized_bubble_sort(arr3)
    print(f"Sorted array (optimized, already sorted): {arr3}")
